using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve "Discriminator" so existing 500K documents remain readable and
            // direct SQL queries (WHERE c.Discriminator = 'Product') keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF 9 changed the id format from "EntityType|Key" to just "Key".
            // Preserve the old format so existing documents ("Product|123") stay addressable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .HasJsonPropertyName("id")
                  .ToJsonProperty("id");
        });

        // EF 9 id-generation compat: keep "EntityType|KeyValue" format
        modelBuilder.Entity<Product>()
            .Property(p => p.Id)
            .HasValueGenerator<LegacyCosmosIdGenerator>();

        // HasIndex is not supported by the Cosmos provider — removed.
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF 9 Cosmos provider removed synchronous query support.
        // All queries must use async APIs (ToListAsync, FirstAsync, etc.).
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = string.Empty;
}

