            // direct SQL queries (WHERE c.Discriminator = 'Product') keep working.
            entity.HasDiscriminator<string>("Discriminator");
        });

        // HasIndex is not supported by the Cosmos provider — removed.
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF 9 Cosmos provider removed synchronous query support.
        // All queries must use async APIs (ToListAsync, FirstAsync, etc.).
    }
}

